"use client";

/**
 * @file Shared Once UI app shell for Moon's Next-based user experience.
 */

import {useEffect, useMemo, useState} from "react";
import Link from "next/link";
import {usePathname} from "next/navigation";
import {
  Button,
  Column,
  Flex,
  MegaMenu,
  MobileMegaMenu,
  Text
} from "@once-ui-system/core";
import {loadMoonChromeContext} from "../lib/api.js";
import {buildLibraryPath, canAccessAdmin, classifyPathname, formatTypeLabel, getLibraryTypes} from "../lib/routes.js";
import ProfileMenu from "./ProfileMenu.jsx";
import SiteFooter from "./SiteFooter.jsx";

const routeDescriptions = {
  home: "Continue reading, pick up fresh releases, and keep your queue moving.",
  browse: "Search by story, mood, and metadata across the whole Scriptarr library.",
  library: "Jump through every tracked type with a denser Kavita-inspired reading surface.",
  title: "Review metadata, recent chapters, follow state, and queue activity in one place.",
  reader: "Full-page Moon reading with seamless chapters, bookmarks, and fast source-backed pages.",
  requests: "Track Moon and Discord requests from the same moderated flow.",
  following: "Stay close to the titles you want Moon and Noona to surface first."
};

/**
 * Build MegaMenu groups for the Moon user shell.
 *
 * @param {string} pathname
 * @returns {import("@once-ui-system/core").MenuGroup[]}
 */
const buildMenuGroups = (pathname) => {
  const active = classifyPathname(pathname);
  const librarySections = [
    {
      title: "Overview",
      links: [
        {
          label: "All library types",
          href: "/library",
          description: "Browse every tracked series in one denser library index.",
          selected: active === "library" && pathname === "/library"
        }
      ]
    },
    {
      title: "Types",
      links: getLibraryTypes().map((entry) => ({
        label: entry.label,
        href: buildLibraryPath(entry.slug),
        description: `Open the ${entry.label.toLowerCase()} shelf.`,
        selected: pathname === buildLibraryPath(entry.slug)
      }))
    }
  ];

  return [
    {
      id: "home",
      label: "Home",
      href: "/",
      selected: active === "home"
    },
    {
      id: "browse",
      label: "Browse",
      href: "/browse",
      selected: active === "browse"
    },
    {
      id: "library",
      label: "Library",
      selected: active === "library" || active === "title" || active === "reader",
      sections: librarySections
    },
    {
      id: "requests",
      label: "Requests",
      href: "/myrequests",
      selected: active === "requests"
    },
    {
      id: "following",
      label: "Following",
      href: "/following",
      selected: active === "following"
    }
  ];
};

/**
 * Wrap every user page in Moon's Once UI shell.
 *
 * @param {{children: import("react").ReactNode}} props
 * @returns {import("react").ReactNode}
 */
export const MoonShell = ({children}) => {
  const pathname = usePathname();
  const [chrome, setChrome] = useState({
    branding: {siteName: "Scriptarr"},
    auth: null,
    bootstrap: null,
    loginUrl: ""
  });
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const [installPrompt, setInstallPrompt] = useState(null);

  useEffect(() => {
    let active = true;
    void loadMoonChromeContext().then((nextValue) => {
      if (active) {
        setChrome(nextValue);
      }
    });

    return () => {
      active = false;
    };
  }, [pathname]);

  useEffect(() => {
    const handleBeforeInstallPrompt = (event) => {
      event.preventDefault();
      setInstallPrompt(event);
    };
    window.addEventListener("beforeinstallprompt", handleBeforeInstallPrompt);
    return () => window.removeEventListener("beforeinstallprompt", handleBeforeInstallPrompt);
  }, []);

  const menuGroups = useMemo(() => buildMenuGroups(pathname), [pathname]);
  const title = chrome.branding?.siteName || "Scriptarr";
  const activeDescription = routeDescriptions[classifyPathname(pathname)] || routeDescriptions.home;

  return (
    <div className="moon-app-shell">
      <header className="moon-header">
        <div className="moon-header-top">
          <Link className="moon-brandmark" href="/">
            <span className="moon-brandmark-badge">S</span>
            <div>
              <span className="moon-brandmark-kicker">Scriptarr Moon</span>
              <strong>{title}</strong>
            </div>
          </Link>
          <Flex gap="12" vertical="center">
            {installPrompt ? (
              <Button
                variant="secondary"
                size="m"
                onClick={async () => {
                  await installPrompt.prompt();
                  setInstallPrompt(null);
                }}
              >
                Install app
              </Button>
            ) : null}
            <ProfileMenu user={chrome.auth} loginUrl={chrome.loginUrl} />
          </Flex>
        </div>
        <div className="moon-header-bottom">
          <div className="moon-header-copy">
            <Text variant="display-strong-l">{title}</Text>
            <Text variant="body-default-m" onBackground="neutral-weak">
              {activeDescription}
            </Text>
          </div>
          <div className="moon-nav-desktop">
            <MegaMenu menuGroups={menuGroups} />
          </div>
          <div className="moon-nav-mobile">
            <button
              className="moon-mobile-menu-trigger"
              type="button"
              onClick={() => setMobileMenuOpen((value) => !value)}
            >
              {mobileMenuOpen ? "Close menu" : "Open menu"}
            </button>
            {mobileMenuOpen ? (
              <div className="moon-mobile-menu-surface">
                <MobileMegaMenu menuGroups={menuGroups} onClose={() => setMobileMenuOpen(false)} />
                {canAccessAdmin(chrome.auth) ? (
                  <div className="moon-mobile-admin-link">
                    <Link href="/admin">Open admin</Link>
                  </div>
                ) : null}
              </div>
            ) : null}
          </div>
        </div>
        <div className="moon-library-type-rail" aria-label="Library types">
          {getLibraryTypes().map((entry) => (
            <Link key={entry.slug} href={buildLibraryPath(entry.slug)} className="moon-type-pill">
              {formatTypeLabel(entry.label)}
            </Link>
          ))}
        </div>
      </header>
      <main className="moon-main-stage">{children}</main>
      <SiteFooter siteName={title} />
    </div>
  );
};

export default MoonShell;
