"use client";

/**
 * @file Profile menu with Once UI Avatar, ContextMenu, and StylePanel.
 */

import Link from "next/link";
import {Avatar, Button, Column, ContextMenu, Flex, StylePanel, Text} from "@once-ui-system/core";
import {canAccessAdmin} from "../lib/routes.js";

const initialsFromName = (value) =>
  String(value || "Reader")
    .split(/\s+/)
    .filter(Boolean)
    .slice(0, 2)
    .map((part) => part.charAt(0).toUpperCase())
    .join("") || "R";

/**
 * Render the signed-in user menu.
 *
 * @param {{
 *   user: {username?: string, role?: string, permissions?: string[], avatarUrl?: string} | null,
 *   loginUrl: string
 * }} props
 * @returns {import("react").ReactNode}
 */
export const ProfileMenu = ({user, loginUrl}) => {
  const dropdown = (
    <Column gap="16" className="moon-profile-dropdown">
      <Flex gap="12" vertical="center">
        <Avatar
          size="l"
          src={user?.avatarUrl || undefined}
          value={initialsFromName(user?.username)}
        />
        <Column gap="4">
          <Text variant="label-default-s">Account</Text>
          <Text variant="heading-strong-s">{user?.username || "Not signed in"}</Text>
          <Text variant="body-default-s" onBackground="neutral-weak">
            {user?.role || "Use Discord login to start reading."}
          </Text>
        </Column>
      </Flex>
      <Flex gap="8" wrap>
        {!user && loginUrl ? (
          <Button href={loginUrl} variant="primary" size="m">
            Discord login
          </Button>
        ) : null}
        <Button href="/myrequests" variant="secondary" size="m">
          My requests
        </Button>
        {canAccessAdmin(user) ? (
          <Button href="/admin" variant="secondary" size="m">
            Admin
          </Button>
        ) : null}
      </Flex>
      <StylePanel />
      <Text variant="body-default-xs" onBackground="neutral-weak">
        Style changes stay on this browser so every device can keep its own reading vibe.
      </Text>
    </Column>
  );

  return (
    <ContextMenu
      placement="bottom-end"
      minWidth={360}
      maxWidth={420}
      dropdown={dropdown}
      className="moon-profile-menu"
    >
      <button className="moon-avatar-trigger" type="button" aria-label="Open profile menu">
        <Avatar
          size="l"
          src={user?.avatarUrl || undefined}
          value={initialsFromName(user?.username)}
        />
      </button>
    </ContextMenu>
  );
};

export default ProfileMenu;
